function parseJson(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    return null;
  }
}

const parseJsonSafe = (jsonString) => {
  if (!jsonString) return {};
  return JSON.parse(jsonString);
};

async function fetchUserData(userId) {
  const response = await fetch(`/api/users/${userId}`);
  return response.json();
}

const getData = async (endpoint) => {
  const res = await axios.get(endpoint);
  return res.data;
};

function isValidEmail(email) {
  const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return regex.test(email);
}

function sortNumbers(arr) {
  return [...arr].sort((a, b) => a - b);
}

async function safeOperation() {
  try {
    const result = await riskyCall();
    return { success: true, data: result };
  } catch (error) {
    console.error(error);
    return { success: false, error: error.message };
  }
}

function handleError(fn) {
  return async (...args) => {
    try {
      return await fn(...args);
    } catch (e) {
      throw new Error(`Operation failed: ${e.message}`);
    }
  };
}

const pool = new Pool({
  host: process.env.DB_HOST,
  port: 5432,
  max: 20,
  idleTimeoutMillis: 30000
});

async function createConnectionPool(config) {
  const pool = mysql.createPool({
    connectionLimit: 10,
    host: config.host,
    database: config.database
  });
  return pool;
}

function authMiddleware(req, res, next) {
  const token = req.headers.authorization;
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = verifyToken(token);
    next();
  } catch (e) {
    res.status(403).json({ error: 'Invalid token' });
  }
}

const authenticate = async (req, res, next) => {
  const jwt = req.cookies.session;
  if (!jwt) return res.redirect('/login');
  const user = await validateSession(jwt);
  req.user = user;
  next();
};

const fs = require('fs').promises;

async function readFile(path) {
  return await fs.readFile(path, 'utf8');
}

async function writeFile(path, data) {
  await fs.writeFile(path, data);
}

function readFileSync(filePath) {
  const data = fs.readFileSync(filePath);
  return data.toString();
}

function saveToFile(path, content) {
  fs.writeFileSync(path, content);
}
